import{_ as e,o as a,c as t,j as r,a as n,a1 as i}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"Cinq协会决斗剑术","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/Cinq协会决斗剑术.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/Cinq协会决斗剑术.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/白刃类/Cinq协会决斗剑术.md"};function s(o,b,d,_,l,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"cinq协会决斗剑术",tabindex:"-1"},[n("Cinq协会决斗剑术 "),r("a",{class:"header-anchor",href:"#cinq协会决斗剑术","aria-label":'Permalink to "Cinq协会决斗剑术"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调012")])])],-1),i('<h1 id="cinq协会决斗剑术-1" tabindex="-1">Cinq协会决斗剑术 <a class="header-anchor" href="#cinq协会决斗剑术-1" aria-label="Permalink to &quot;Cinq协会决斗剑术&quot;">​</a></h1><p>Cinq协会决斗剑术</p><p>【呼吸】<br> 拥有该词条的单位在进行一次以生理属性作为关键属性的攻击前须投掷一个D10的自然骰，若出目不大于呼吸层数，则令这次攻击造成的伤害增加一半并消耗一层呼吸层数。<br> 一个单位的具有呼吸层数上限为10层。<br> 呼吸层数会在战斗结束时清空。</p><p>以下能力均需要以造成穿刺伤害的剑类武器使用，攻击造成的物理伤害性质默认为穿刺伤害。</p><p>前进<br> D+750<br> 迅速而有力的踏入敌人身前发起一次剑击，阻断敌人的攻击节奏。<br> 使用动作：标准<br> 持续时间：立即<br> 效果：进行一次近战攻击，这次攻击具有3点速度加值。<br> 攻击命中后令自身的先攻值在一轮内提升4点，并获得1层【呼吸】。<br> 额外支付D+500:<br> 攻击命中后，再获得1层【呼吸】。<br> 受到攻击伤害的单位需要进行一次反射豁免，DC为此次攻击的伤害值。失败则在一轮内仅能指定使用者为攻击目标，这是一个C级别创伤来源的胁迫效果。</p><p>惩罚<br> C+1000<br> 轮转剑刃迷惑敌方并趁机将其击倒，紧接着旋剑向下刺入倒地的躯体。<br> 使用动作：标准<br> 持续时间：立即<br> 效果：<br> 当人物的先攻顺位高于目标时，在本招式进行的拌摔检定与攻击检定上获得6点增强加值。<br> 选择一个触及范围内的敌方单位，以敏捷+武技+剑进行一次绊摔检定，对方以敏捷+运动+平衡/反射对抗，失败则陷入伏地状态。<br> 接着人物对其进行一次近战攻击，攻击命中后人物获得1层【呼吸】。<br> 受到攻击伤害的单位需要进行一次强韧豁免，DC为此次攻击造成的伤害值。失败则在一轮内仅能指定使用者为攻击目标，这是一个C级别创伤来源的胁迫效果。<br> 此外，受到攻击伤害的单位，其先攻值还会在一轮内降低6点。<br> 额外支付D+500:<br> 当人物的先攻顺位高于目标时，在本招式进行的绊摔检定与攻击检定上再获得6点增强加值。<br> 攻击命中后，再获得1层【呼吸】。</p><p>腾跃长刺<br> C+1000<br> 短暂地收缩身体进行蓄力，进而将自身作为弹簧一般把所有积蓄的势能集中在手中的剑尖之上，猝然间将敌人洞穿。<br> 使用动作：整轮<br> 持续时间：立即<br> 限制：每场景一次<br> 效果：<br> 若使用此招式时，人物的呼吸层数不低于7层，则此次冲锋不承受基础防御减值且攻击获得等于敏捷值的速度加值。<br> 对一个单位进行一次冲锋，这次冲锋具有B级别措手不及。<br> 若这次冲锋攻击触发了【呼吸】的伤害增加效果，则令这次攻击造成的伤害再增加一半。</p><p>延续进攻<br> D+750<br> 人物的前踏突刺让对方应接不暇。<br> 使用动作：标准<br> 持续时间：立即<br> 效果：<br> 进行一次攻击，命中后获得一层【呼吸】并在一轮内提升10点先攻。<br> 额外支付D+500:<br> 当人物的先攻顺位高于目标时，这次攻击获得6点速度加值。<br> 攻击命中后再获得一层【呼吸】。</p><p>交战<br> 前置：延续进攻<br> C+1000<br> 下撩、侧击、突刺，以无懈可击的剑术与精湛的步伐将敌人一步一步拖入你的战斗节奏。<br> 使用动作：标准<br> 持续时间：立即<br> 效果：<br> 对一个单位进行一次近战攻击。<br> 若人物的先攻顺位高于敌方单位，则自身的先攻值每高于目标1点，就在这次攻击中获得1点速度加值，上限为人物敏捷属性的一半。<br> 攻击命中后，自身获得1层【呼吸】。<br> 受到伤害的目标需要进行一次强韧豁免，DC为伤害值，失败则在一轮内陷入C级创伤来源的迟滞状态。<br> 额外支付C+1000：<br> 从本技能中获得的速度加值上限提升至敏捷属性的1.5倍。<br> 攻击命中后，自身再获得2层【呼吸】。<br> 迟滞状态的来源等级提升至B级。</p><p>反攻<br> B+2000<br> “准备好了吗？”<br> “那么”<br> “凝视…剑锋——”<br> 刹那间，湛蓝色的剑锋便已经洞穿对方心口，剑锋穿刺空气后留下的是片片天鹅绒般的光羽。<br> 使用需求：人物身上至少具有6层【呼吸】<br> 使用间隔：两轮<br> 使用动作：整轮<br> 持续时间：立即<br> 效果：<br> 对一个目标进行一次冲锋，这次冲锋攻击不承受基础防御减值，并且具有A级措手不及。<br> 若人物的先攻顺位高于所有敌方单位，则自身的先攻值每高于目标1点，就在这次冲锋攻击中获得1点速度加值，上限为人物敏捷属性的二倍。<br> 若这次攻击触发了【呼吸】的伤害增加效果，令此伤害再增加一半。<br> 若人物自身具有10层【呼吸】，则此次攻击造成的伤害再增加一倍。<br> 这次冲锋结束以后，人物的【呼吸】层数下降5层。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const q=e(p,[["render",s]]);export{h as __pageData,q as default};
